+
+class MatchEachExpression {
+  constructor(
+    private readonly hasInput: boolean,
+    private readonly input: unknown,
+    private readonly operations: readonly Operation[]
+  ) {}
+
+  with(...args: any[]): MatchEachExpression {
+    const handler = args[args.length - 1] as Clause['handler'];
+    const patterns: Pattern<unknown>[] = [args[0]];
+    let predicate: Clause['predicate'];
+
+    if (args.length === 3 && typeof args[1] === 'function') {
+      predicate = args[1];
+    } else if (args.length > 2) {
+      patterns.push(...args.slice(1, -1));
+    }
+
+    return this.add({ patterns, predicate, handler });
+  }
+
+  when(
+    predicate: (value: unknown) => unknown,
+    handler: (value: unknown, input: unknown) => unknown
+  ): MatchEachExpression {
+    return this.add({
+      patterns: [],
+      predicate,
+      handler: (_selection, value) => handler(value, value),
+    });
+  }
+
+  tap(callback: (result: unknown) => unknown): MatchEachExpression {
+    return this.add({ tap: callback });
+  }
+
+  otherwise(handler: (value: unknown) => unknown): unknown[] {
+    return this.evaluate(this.input, handler, false)!;
+  }
+
+  exhaustive(handler?: (value: unknown) => unknown): unknown[] {
+    return this.evaluate(this.input, handler, false)!;
+  }
+
+  run(): unknown[] {
+    return this.evaluate(this.input, undefined, false)!;
+  }
+
+  returnType(): this {
+    return this;
+  }
+
+  narrow(): this {
+    return this;
+  }
+
+  toFunction(): (input: unknown) => unknown[] {
+    return (input) => this.evaluate(input, undefined, false)!;
+  }
+
+  toExhaustiveFunction(): (input: unknown) => unknown[] {
+    return this.toFunction();
+  }
+
+  toPartialFunction(): (input: unknown) => unknown[] | undefined {
+    return (input) => this.evaluate(input, undefined, true);
+  }
+
+  private add(operation: Operation): MatchEachExpression {
+    return new MatchEachExpression(this.hasInput, this.input, [
+      ...this.operations,
+      operation,
+    ]);
+  }
+
+  private evaluate(
+    input: unknown,
+    fallback: ((value: unknown) => unknown) | undefined,
+    partial: boolean
+  ): unknown[] | undefined {
+    const results: unknown[] = [];
+
+    for (const operation of this.operations) {
+      if ('tap' in operation) {
+        results.forEach(operation.tap);
+        continue;
+      }
+
+      const selection = this.match(operation, input);
+      if (selection.matched) {
+        results.push(operation.handler(selection.value, input));
